import{bQ as d,aL as a,u as e,G as r}from"./chunks/framework.D06dwy5q.js";const b=JSON.parse('{"title":"02｜堡垒机与访问审计","description":"","frontmatter":{},"headers":[],"relativePath":"03.远程运维/02-堡垒机与访问审计.md","filePath":"03.远程运维/02-堡垒机与访问审计.md","lastUpdated":null}'),s={name:"03.远程运维/02-堡垒机与访问审计.md"};function i(h,t,o,n,l,p){return a(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="_02-堡垒机与访问审计" tabindex="-1">02｜堡垒机与访问审计 <a class="header-anchor" href="#_02-堡垒机与访问审计" aria-label="Permalink to &quot;02｜堡垒机与访问审计&quot;">​</a></h1><p>上一篇用 SSH 直连服务器。机器不多、人就自己一个时，直连很方便。但机器和人员一多，几个问题就冒出来：同事离职了，他本地的 SSH 密钥还在不在？几个人共用 root，出了问题谁干的？临时给外包开个账号，事完忘了收回。</p><table tabindex="0"><thead><tr><th>问题</th><th>直连 SSH 的表现</th></tr></thead><tbody><tr><td>权限管理</td><td>本地账号+口头约定，离职时逐台清理密钥</td></tr><tr><td>操作追溯</td><td>多人共用 root，无法区分具体操作人</td></tr><tr><td>高危命令</td><td>执行完才知道，无事前拦截</td></tr><tr><td>临时授权</td><td>口头答应，过期了没人记得收回</td></tr></tbody></table><p>堡垒机把这些入口收回一个点：所有人先登录堡垒机，再由堡垒机连接资产。核心价值是<strong>谁、在什么时间、通过什么账号、对哪台机器、做了什么——全链路审计</strong>。本篇以 JumpServer 为例讲堡垒机的核心对象、权限模型、审计能力，原理适用于同类产品。</p><h2 id="一、核心对象关系" tabindex="-1">一、核心对象关系 <a class="header-anchor" href="#一、核心对象关系" aria-label="Permalink to &quot;一、核心对象关系&quot;">​</a></h2><p>堡垒机最容易搞混的是几类对象:</p><table tabindex="0"><thead><tr><th>对象</th><th>含义</th><th>示例</th></tr></thead><tbody><tr><td><strong>用户</strong></td><td>登录堡垒机的人</td><td><code>admin</code>、<code>ops01</code></td></tr><tr><td><strong>资产</strong></td><td>被管理的目标资源</td><td>Linux 主机、Windows、数据库</td></tr><tr><td><strong>账号</strong></td><td><strong>资产上的系统登录身份</strong>(不是堡垒机用户)</td><td><code>root</code>、<code>deploy</code></td></tr><tr><td><strong>授权规则</strong></td><td>规定哪个人可以用哪个账号访问哪些资产</td><td><code>admin</code> → <code>root@192.168.10.129</code></td></tr><tr><td><strong>审计</strong></td><td>连接过程、命令、录像</td><td>连接日志、命令记录、会话回放</td></tr></tbody></table><p>关系一句话概括:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户通过堡垒机,被授权使用某个资产账号,连接某台资产。</span></span></code></pre></div><p><strong>只创建资产不够</strong>——资产告诉堡垒机&quot;这台机器存在&quot;,账号表示&quot;用什么身份登录&quot;,授权表示&quot;这个人可以使用这个身份&quot;。缺任何一块最终都连不上。新手最常踩的坑:资产建了、账号建了,但忘了做授权。</p><h2 id="二、jumpserver-实验环境" tabindex="-1">二、JumpServer 实验环境 <a class="header-anchor" href="#二、jumpserver-实验环境" aria-label="Permalink to &quot;二、JumpServer 实验环境&quot;">​</a></h2><table tabindex="0"><thead><tr><th>组件</th><th>地址</th></tr></thead><tbody><tr><td>JumpServer</td><td><code>http://192.168.10.11/</code></td></tr><tr><td>被管理主机</td><td><code>192.168.10.129</code></td></tr><tr><td>堡垒机管理员</td><td><code>admin</code></td></tr><tr><td>资产账号</td><td><code>root</code></td></tr></tbody></table><h3 id="登录入口" tabindex="-1">登录入口 <a class="header-anchor" href="#登录入口" aria-label="Permalink to &quot;登录入口&quot;">​</a></h3><p>打开浏览器访问 <code>http://192.168.10.11/</code>,使用 <code>admin</code> 账号登录。控制台展示平台概览——资产、用户、会话等对象入口。</p><p><strong>实验环境使用简单密码;生产环境必须开启 MFA、强密码策略、来源 IP 限制。</strong></p><h2 id="三、资产纳管" tabindex="-1">三、资产纳管 <a class="header-anchor" href="#三、资产纳管" aria-label="Permalink to &quot;三、资产纳管&quot;">​</a></h2><h3 id="创建资产" tabindex="-1">创建资产 <a class="header-anchor" href="#创建资产" aria-label="Permalink to &quot;创建资产&quot;">​</a></h3><p>导航:进入 JumpServer,左侧菜单「资产管理」→「资产列表」→「创建资产」</p><table tabindex="0"><thead><tr><th>字段</th><th>推荐值</th><th>说明</th></tr></thead><tbody><tr><td>名称</td><td><code>test-rocky-192.168.10.129</code></td><td>建议名字带地址,排查时一眼识别</td></tr><tr><td>IP/主机</td><td><code>192.168.10.129</code></td><td>堡垒机连接资产的实际地址</td></tr><tr><td>平台</td><td><code>Linux</code></td><td>决定协议类型与连接方式</td></tr><tr><td>协议</td><td><code>SSH</code> + <code>SFTP</code></td><td>Linux 主机至少 SSH</td></tr><tr><td>节点</td><td><code>/默认/</code></td><td>按节点批量授权</td></tr></tbody></table><p><strong>名称建议带地址</strong>,如 <code>test-rocky-192.168.10.129</code>——纯业务名(<code>web-prod-03</code>)需要想一下是哪台,带地址的 <code>web-prod-03-10.0.1.23</code> 一目了然。</p><p><strong>密码、Token 等敏感信息不要放在备注里。</strong></p><h2 id="四、资产账号" tabindex="-1">四、资产账号 <a class="header-anchor" href="#四、资产账号" aria-label="Permalink to &quot;四、资产账号&quot;">​</a></h2><h3 id="创建账号" tabindex="-1">创建账号 <a class="header-anchor" href="#创建账号" aria-label="Permalink to &quot;创建账号&quot;">​</a></h3><p>导航:进入资产详情 →「账号」→「创建账号」</p><table tabindex="0"><thead><tr><th>字段</th><th>推荐值</th><th>说明</th></tr></thead><tbody><tr><td>用户名</td><td><code>root</code></td><td>目标主机上的登录用户名</td></tr><tr><td>密码/密钥</td><td>托管密码或私钥</td><td><strong>凭据由堡垒机托管,用户不需要知道真实密码</strong></td></tr><tr><td>权限</td><td><code>密文</code></td><td>表示JumpServer保管了认证凭据</td></tr></tbody></table><p><strong>凭据统一托管在堡垒机,用户不需要知道目标机器的真实密码。</strong></p><h3 id="凭据托管的含义" tabindex="-1">凭据托管的含义 <a class="header-anchor" href="#凭据托管的含义" aria-label="Permalink to &quot;凭据托管的含义&quot;">​</a></h3><p>账号列表的 <code>密文</code> 状态表示 JumpServer 保存了凭据。好处是用户只需通过授权即可访问,<strong>不需要接触真实的密码或私钥</strong>。</p><h3 id="账号管理的几种方式" tabindex="-1">账号管理的几种方式 <a class="header-anchor" href="#账号管理的几种方式" aria-label="Permalink to &quot;账号管理的几种方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方式</th><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td>托管密码</td><td>用户不需要知道真实密码</td><td>堡垒机被攻破后凭据全部暴露</td></tr><tr><td>托管私钥</td><td>适合批量 Linux 主机管理</td><td>私钥需定期轮换</td></tr><tr><td>手动输入</td><td>临时连接,审计仍在</td><td>每次输入,体验差</td></tr><tr><td>个人账号+sudo</td><td>责任清晰,可追溯具体人</td><td>账号生命周期管理复杂</td></tr></tbody></table><p><strong>生产推荐:个人账号 + sudo + 命令审计。root 保留给少数应急场景,日常操作走个人身份。</strong></p><h2 id="五、授权规则" tabindex="-1">五、授权规则 <a class="header-anchor" href="#五、授权规则" aria-label="Permalink to &quot;五、授权规则&quot;">​</a></h2><p>授权规则把用户、资产、账号串联起来。</p><h3 id="创建授权" tabindex="-1">创建授权 <a class="header-anchor" href="#创建授权" aria-label="Permalink to &quot;创建授权&quot;">​</a></h3><p>导航:左侧菜单「权限管理」→「授权规则」→「创建授权」</p><table tabindex="0"><thead><tr><th>区域</th><th>字段</th><th>配置要点</th></tr></thead><tbody><tr><td>基本信息</td><td>名称</td><td>说明谁对什么资产的授权</td></tr><tr><td>用户/用户组</td><td>选择用户</td><td>哪些堡垒机用户可用此授权,建议按用户组权限管理</td></tr><tr><td>资产/节点</td><td>选择资产</td><td>授权到具体资产或节点(建议节点:加入节点的资产自动获得授权)</td></tr><tr><td>账号</td><td>选择账号</td><td>允许使用哪些资产账号(如 root、deploy)</td></tr><tr><td>协议</td><td>SSH/SFTP/RDP</td><td>按需勾选</td></tr><tr><td>动作</td><td>连接/文件传输</td><td>按需勾选,谨慎开放文件传输</td></tr><tr><td>有效期</td><td>开始和结束时间</td><td><strong>临时授权必须设过期时间,到期自动失效</strong></td></tr></tbody></table><h3 id="授权规则的风险信号" tabindex="-1">授权规则的风险信号 <a class="header-anchor" href="#授权规则的风险信号" aria-label="Permalink to &quot;授权规则的风险信号&quot;">​</a></h3><table tabindex="0"><thead><tr><th>风险</th><th>处理</th></tr></thead><tbody><tr><td>所有人授权所有资产</td><td>权限面太大,人员变动难收敛</td></tr><tr><td>所有账号都可用</td><td>用户可随意选高权限账号,绕过最小权限原则</td></tr><tr><td>永不过期的临时授权</td><td>过期自动失效比人记更可靠</td></tr><tr><td>同时开放文件传输+剪贴板</td><td>数据带出风险增高</td></tr></tbody></table><p><strong>临时排除时需要高权限时,在授权规则里设过期时间,到期自动失效。</strong></p><h2 id="六、web-terminal-连接" tabindex="-1">六、Web Terminal 连接 <a class="header-anchor" href="#六、web-terminal-连接" aria-label="Permalink to &quot;六、Web Terminal 连接&quot;">​</a></h2><p>普通用户进入 JumpServer 的「Web Terminal」(Luna)后,只能看到被授权的资产树——<strong>没授权的资产不显示</strong>。</p><h3 id="连接步骤" tabindex="-1">连接步骤 <a class="header-anchor" href="#连接步骤" aria-label="Permalink to &quot;连接步骤&quot;">​</a></h3><ol><li>登录 JumpServer Web 控制台</li><li>进入「Web Terminal」(Luna)</li><li>在资产树中选择目标资产</li><li>确认连接弹窗中的信息:</li></ol><table tabindex="0"><thead><tr><th>字段</th><th>值</th></tr></thead><tbody><tr><td>协议</td><td>SSH</td></tr><tr><td>账号</td><td>root(资产托管的)</td></tr><tr><td>连接方式</td><td>Web CLI</td></tr></tbody></table><ol start="5"><li>点击连接,浏览器中打开终端</li></ol><h3 id="连接后确认" tabindex="-1">连接后确认 <a class="header-anchor" href="#连接后确认" aria-label="Permalink to &quot;连接后确认&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">whoami</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 确认当前系统用户</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hostname</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 确认目标 IP,避免连错机器</span></span></code></pre></div><p><strong>远程运维的习惯:连上后先确认身份、主机名、IP,再动手改配置——能避免&quot;改错机器&quot;这种灾难性事故。</strong></p><h2 id="七、审计能力与局限" tabindex="-1">七、审计能力与局限 <a class="header-anchor" href="#七、审计能力与局限" aria-label="Permalink to &quot;七、审计能力与局限&quot;">​</a></h2><h3 id="堡垒机通常提供的审计能力" tabindex="-1">堡垒机通常提供的审计能力 <a class="header-anchor" href="#堡垒机通常提供的审计能力" aria-label="Permalink to &quot;堡垒机通常提供的审计能力&quot;">​</a></h3><table tabindex="0"><thead><tr><th>审计类型</th><th>内容</th><th>用途</th></tr></thead><tbody><tr><td>登录日志</td><td>谁在什么时间、从什么 IP 登录堡垒机</td><td>异常来源发现</td></tr><tr><td>连接日志</td><td>谁连接了哪台资产、用了什么账号</td><td>操作追溯</td></tr><tr><td>命令记录</td><td>SSH 会话中执行的命令</td><td>操作审计</td></tr><tr><td>会话录像</td><td>完整的交互过程回放</td><td>事故复盘</td></tr><tr><td>文件传输</td><td>上传/下载/SFTP 操作</td><td>数据防泄漏</td></tr><tr><td>改密记录</td><td>托管密码是否按时轮换</td><td>合规检查</td></tr></tbody></table><h3 id="命令审计的覆盖盲区" tabindex="-1">命令审计的覆盖盲区 <a class="header-anchor" href="#命令审计的覆盖盲区" aria-label="Permalink to &quot;命令审计的覆盖盲区&quot;">​</a></h3><table tabindex="0"><thead><tr><th>盲区</th><th>具体表现</th></tr></thead><tbody><tr><td>交互程序</td><td><code>vim</code>、<code>mysql</code>、<code>redis-cli</code> 内部操作不全</td></tr><tr><td>执行脚本</td><td>只记录 <code>bash deploy.sh</code>,脚本内部内容看脚本自身</td></tr><tr><td>二进制工具</td><td>记录 <code>kill 1234</code>,但不知 1234 是哪个进程</td></tr><tr><td>SFTP</td><td>终端命令记录看不到文件传输</td></tr></tbody></table><p>堡垒机是远程入口治理的一个环节,<strong>不是全部工具</strong>。命令审计 + 应用日志 + 数据库审计结合起来,才能完整还原一次操作的全貌。</p><h2 id="八、mfa-与登录保护" tabindex="-1">八、MFA 与登录保护 <a class="header-anchor" href="#八、mfa-与登录保护" aria-label="Permalink to &quot;八、MFA 与登录保护&quot;">​</a></h2><p><strong>堡垒机能连接大量资产,入口的登录认证需要比普通系统更严格。</strong> 一台服务器被攻破是单点损失;堡垒机密码泄露就等于所有资产的访问权。</p><table tabindex="0"><thead><tr><th>措施</th><th>作用</th></tr></thead><tbody><tr><td>MFA(多因素认证)</td><td>密码加动态码/硬件令牌,拿到密码也登录不了</td></tr><tr><td>强密码策略</td><td>降低弱口令被撞库的风险</td></tr><tr><td>登录失败锁定</td><td>连续错误后锁定,防暴力破解</td></tr><tr><td>来源 IP 限制</td><td>只允许办公网/VPN 访问堡垒机入口</td></tr><tr><td>管理员账号一人一个</td><td>审计日志才能精确到人</td></tr><tr><td>定期审计管理员</td><td>及时清理离职/转岗残留权限</td></tr></tbody></table><p><strong>管理员账号如果多人共用一个,审计日志只能记录&quot;admin 做了什么&quot;,追踪不到具体责任人。</strong></p><h2 id="九、常见故障排查" tabindex="-1">九、常见故障排查 <a class="header-anchor" href="#九、常见故障排查" aria-label="Permalink to &quot;九、常见故障排查&quot;">​</a></h2><h3 id="资产可见但无可用账号" tabindex="-1">资产可见但无可用账号 <a class="header-anchor" href="#资产可见但无可用账号" aria-label="Permalink to &quot;资产可见但无可用账号&quot;">​</a></h3><p><strong>现象</strong>:Luna 中能看到资产,点击连接时提示没有可用账号。</p><p>排查顺序:</p><table tabindex="0"><thead><tr><th>步骤</th><th>检查项</th><th>要确认什么</th></tr></thead><tbody><tr><td>1</td><td>资产是否存在</td><td>资产列表中有目标机器</td></tr><tr><td>2</td><td>账号是否绑定</td><td>账号列表中有对应资产的账号</td></tr><tr><td>3</td><td>授权规则是否包含此账号</td><td>规则&quot;账号&quot;栏勾选了此账号</td></tr><tr><td>4</td><td>授权是否对用户生效</td><td>用户/用户组匹配,启用状态正常,在有效期内</td></tr><tr><td>5</td><td>协议是否匹配</td><td>SSH 资产需要授权规则包含 SSH 协议</td></tr></tbody></table><p><strong>只授权了资产但没有授权账号,就会出现&quot;看得到但连不上&quot;。</strong></p><h3 id="连接失败-两段排查" tabindex="-1">连接失败:两段排查 <a class="header-anchor" href="#连接失败-两段排查" aria-label="Permalink to &quot;连接失败:两段排查&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户 → JumpServer(第 1 段)</span></span>
<span class="line"><span>JumpServer → 目标资产(第 2 段)</span></span></code></pre></div><p>第 1 段失败:登录堡垒机——账号状态、MFA、浏览器访问。</p><p>第 2 段失败:从 JumpServer 机器测试:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -vz</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.129</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 22</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 端口通?</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> key</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@192.168.10.129</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 认证通?</span></span></code></pre></div><p>端口不通→目标机器防火墙/安全组;认证失败→账号密码/密钥/sshd 配置。</p><h3 id="审计缺命令-确认是否绕过了堡垒机" tabindex="-1">审计缺命令:确认是否绕过了堡垒机 <a class="header-anchor" href="#审计缺命令-确认是否绕过了堡垒机" aria-label="Permalink to &quot;审计缺命令:确认是否绕过了堡垒机&quot;">​</a></h3><p><strong>如果用户还能绕过堡垒机直连目标机器,堡垒机当然审不到。</strong></p><p>目标机器侧收紧来源:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 只允许堡垒机 192.168.10.11 访问 SSH</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">iptables</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INPUT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tcp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dport</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 22</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.11</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ACCEPT</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">iptables</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INPUT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tcp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dport</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 22</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> DROP</span></span></code></pre></div><p><strong>远程改防火墙规则时需要确认:当前连接来源、回滚方式、VNC/控制台入口。</strong> 否则直接 DROP 22 把自己关在外面。</p><h2 id="十、上线关键点" tabindex="-1">十、上线关键点 <a class="header-anchor" href="#十、上线关键点" aria-label="Permalink to &quot;十、上线关键点&quot;">​</a></h2><p>堡垒机上线不是装起来就完工,<strong>真正费力的部分是把资产、用户、授权、审计理顺:</strong></p><table tabindex="0"><thead><tr><th>事项</th><th>做法</th></tr></thead><tbody><tr><td>资产来源</td><td>从 CMDB 或云平台同步,不靠手工维护</td></tr><tr><td>用户来源</td><td>对接 LDAP/AD,员工离职在源头停掉,堡垒机联动失效</td></tr><tr><td>授权模型</td><td>按岗/环境/节点分组授权,不逐个用户配</td></tr><tr><td>高危权限</td><td>root、DBA、生产写权限单独审批</td></tr><tr><td>审计留存</td><td>明确日志和录像保留期,满足合规要求</td></tr><tr><td>绕行治理</td><td>目标资产只允许堡垒机 IP 访问</td></tr><tr><td>应急入口</td><td>堡垒机故障时保留受控的应急登录方式</td></tr></tbody></table><p>上线后定期检查两件事:</p><ol><li><strong>目标资产还能被绕过堡垒机直连吗?</strong>——绕行使审计断掉</li><li><strong>授权规则是否保持过大的范围?</strong>——人员变动后权限没回收</li></ol><p><strong>这两件事不管好,堡垒机就只是个摆设。</strong></p>`,81)])])}const k=d(s,[["render",i]]);export{b as __pageData,k as default};
